			tempPath := tc.Path
			if tc.IsTempDirPath {
				tempDir = t.TempDir()
				tempPath = filepath.Join(tempDir, tempPath)
			}

			sink, err := NewAuditFileSink(tempPath, tc.Format, tc.Options...)

			switch {
