				require.Equal(t, tc.ExpectedFileMode, sink.fileMode)

				switch {
				case tc.IsTempDirPath:
					require.Equal(t, tempPath, sink.path)
				default:
					require.Equal(t, tc.ExpectedPath, sink.path)
				}
			}
		})
